/*
 * Segregated free list allocator with boundary tag coalescing.
 *
 * Block structure:
 *   Allocated: [header(8)] [payload] [footer(8)]
 *   Free:      [header(8)] [prev_ptr(8)] [next_ptr(8)] [...] [footer(8)]
 *
 * Header/footer: 8 bytes, stores block size (low 3 bits = 0) | alloc bit.
 * Minimum block size: 4 * WSIZE = 32 bytes.
 * Block alignment: 8 bytes (WSIZE).
 *
 * Segregated free lists: 12 size classes, heads stored in heap before prologue.
 * Insertion: LIFO (at head of list).
 * Search: first-fit starting from smallest fitting class.
 */

#include <stdbool.h>
#include <stdint.h>
#include <stdio.h>
#include <string.h>

#include "memlib.h"
#include "mm.h"

/*********************************************************
 * NOTE TO STUDENTS: Before you do anything else, please
 * provide your team information in the following struct.
 ********************************************************/
team_t team = {
	/* Team name */
	"BSCS Bench",
	/* First member's full name */
	"BSCS Bench Agent",
	/* First member's NetID */
	"bscs1",
	/* Second member's full name (leave blank if none) */
	"",
	/* Second member's NetID (leave blank if none) */
	""
};

/* Basic constants */
#define WSIZE       sizeof(void *)    /* Word size = 8 bytes on 64-bit */
#define DSIZE       (2 * WSIZE)       /* Doubleword size = 16 bytes */
#define CHUNKSIZE   (1 << 12)         /* Extend heap by this amount */
#define NUM_CLASSES 12                /* Number of segregated size classes */
#define MIN_BLOCK   (4 * WSIZE)       /* Min block: hdr+prev+next+ftr = 32B */

#define MAX(x, y)   ((x) > (y) ? (x) : (y))

/* Pack size and alloc bit into a word */
#define PACK(size, alloc)   ((size) | (alloc))

/* Read/write a word at address p */
#define GET(p)          (*(uintptr_t *)(p))
#define PUT(p, val)     (*(uintptr_t *)(p) = (val))

/* Extract size (mask low 3 bits, 8-byte alignment) and alloc bit */
#define GET_SIZE(p)     (GET(p) & ~(WSIZE - 1))
#define GET_ALLOC(p)    (GET(p) & 0x1)

/* Header and footer of a block with payload pointer bp */
#define HDRP(bp)        ((char *)(bp) - WSIZE)
#define FTRP(bp)        ((char *)(bp) + GET_SIZE(HDRP(bp)) - DSIZE)

/* Next and previous blocks in the heap */
#define NEXT_BLKP(bp)   ((char *)(bp) + GET_SIZE(HDRP(bp)))
#define PREV_BLKP(bp)   ((char *)(bp) - GET_SIZE((char *)(bp) - DSIZE))

/* Prev/next free-block pointers stored in payload area of free block */
#define PREV_FREE(bp)   (*(void **)(bp))
#define NEXT_FREE(bp)   (*(void **)((char *)(bp) + WSIZE))

/* Global variables */
static char *heap_listp;  /* Payload pointer of prologue block */
static char *seg_listp;   /* Pointer to seg-list array in heap */

/* Internal helper prototypes */
static void *coalesce(void *bp);
static void *extend_heap(size_t words);
static void *find_fit(size_t asize);
static void  place(void *bp, size_t asize);
static int   size_class(size_t size);
static void  list_insert(void *bp);
static void  list_remove(void *bp);

/* Heap consistency checker prototypes */
static void checkblock(void *bp);
static void checkheap(bool verbose);
static void printblock(void *bp);

/* ------------------------------------------------------------------
 * Segregated list helpers
 * ------------------------------------------------------------------ */

/* Return the seg-list head pointer for class i */
static inline void *
get_head(int i)
{
	return *(void **)((char *)seg_listp + i * WSIZE);
}

/* Set the seg-list head pointer for class i */
static inline void
set_head(int i, void *ptr)
{
	*(void **)((char *)seg_listp + i * WSIZE) = ptr;
}

/*
 * Return the size class index for a block of the given size.
 * Classes: {<=32}, {<=64}, {<=128}, {<=256}, {<=512}, {<=1024},
 *          {<=2048}, {<=4096}, {<=8192}, {<=16384}, {<=32768}, {>32768}
 */
static int
size_class(size_t size)
{
	if (size <= 32)    return 0;
	if (size <= 64)    return 1;
	if (size <= 128)   return 2;
	if (size <= 256)   return 3;
	if (size <= 512)   return 4;
	if (size <= 1024)  return 5;
	if (size <= 2048)  return 6;
	if (size <= 4096)  return 7;
	if (size <= 8192)  return 8;
	if (size <= 16384) return 9;
	if (size <= 32768) return 10;
	return 11;
}

/* Insert free block bp at the head of its size class list (LIFO) */
static void
list_insert(void *bp)
{
	int cls = size_class(GET_SIZE(HDRP(bp)));
	void *head = get_head(cls);

	PREV_FREE(bp) = NULL;
	NEXT_FREE(bp) = head;
	if (head != NULL)
		PREV_FREE(head) = bp;
	set_head(cls, bp);
}

/* Remove free block bp from its size class list */
static void
list_remove(void *bp)
{
	int cls = size_class(GET_SIZE(HDRP(bp)));
	void *prev = PREV_FREE(bp);
	void *next = NEXT_FREE(bp);

	if (prev != NULL)
		NEXT_FREE(prev) = next;
	else
		set_head(cls, next);

	if (next != NULL)
		PREV_FREE(next) = prev;
}

/* ------------------------------------------------------------------
 * Public interface
 * ------------------------------------------------------------------ */

/*
 * mm_init - Initialize the memory manager. Returns 0 on success, -1 on error.
 *
 * Layout at heap start:
 *   [NUM_CLASSES seg-list heads (8B each)]
 *   [alignment padding (8B)]
 *   [prologue header (8B)]
 *   [prologue footer / heap_listp (8B)]
 *   [epilogue header (8B)]
 */
int
mm_init(void)
{
	size_t init_size = (NUM_CLASSES + 4) * WSIZE;
	char *p;

	if ((seg_listp = (char *)mem_sbrk(init_size)) == (void *)-1)
		return (-1);

	/* Initialize all seg-list heads to NULL */
	for (int i = 0; i < NUM_CLASSES; i++)
		set_head(i, NULL);

	/* Set up prologue and epilogue */
	p = seg_listp + NUM_CLASSES * WSIZE;
	PUT(p,             0);                  /* Alignment padding */
	PUT(p + WSIZE,     PACK(DSIZE, 1));     /* Prologue header */
	PUT(p + 2 * WSIZE, PACK(DSIZE, 1));     /* Prologue footer */
	PUT(p + 3 * WSIZE, PACK(0, 1));         /* Epilogue header */
	heap_listp = p + 2 * WSIZE;

	/* Extend heap with initial free chunk */
	if (extend_heap(CHUNKSIZE / WSIZE) == NULL)
		return (-1);
	return (0);
}

/*
 * mm_malloc - Allocate a block with at least 'size' bytes of payload.
 *   Returns pointer to payload, or NULL if size == 0 or no memory.
 */
void *
mm_malloc(size_t size)
{
	size_t asize;       /* Adjusted block size */
	size_t extendsize;  /* Bytes to extend if no fit */
	void *bp;

	if (size == 0)
		return (NULL);

	/* Round up: payload + header + footer, aligned to WSIZE */
	asize = (size + DSIZE + WSIZE - 1) & ~(WSIZE - 1);
	if (asize < MIN_BLOCK)
		asize = MIN_BLOCK;

	if ((bp = find_fit(asize)) != NULL) {
		place(bp, asize);
		return (bp);
	}

	/* No fit: extend heap */
	extendsize = MAX(asize, CHUNKSIZE);
	if ((bp = extend_heap(extendsize / WSIZE)) == NULL)
		return (NULL);
	place(bp, asize);
	return (bp);
}

/*
 * mm_free - Free the block pointed to by bp.
 */
void
mm_free(void *bp)
{
	size_t size;

	if (bp == NULL)
		return;

	size = GET_SIZE(HDRP(bp));
	PUT(HDRP(bp), PACK(size, 0));
	PUT(FTRP(bp), PACK(size, 0));
	coalesce(bp);
}

/*
 * mm_realloc - Resize the block pointed to by ptr to at least 'size' bytes.
 *   Optimized: absorbs adjacent next free block when possible.
 */
void *
mm_realloc(void *ptr, size_t size)
{
	size_t oldsize, asize, total;
	void *next_bp;
	void *newptr;
	size_t copy_size;

	if (size == 0) {
		mm_free(ptr);
		return (NULL);
	}
	if (ptr == NULL)
		return (mm_malloc(size));

	oldsize = GET_SIZE(HDRP(ptr));
	asize = (size + DSIZE + WSIZE - 1) & ~(WSIZE - 1);
	if (asize < MIN_BLOCK)
		asize = MIN_BLOCK;

	/* Already large enough */
	if (asize <= oldsize)
		return (ptr);

	/* Try to absorb the next free block */
	next_bp = NEXT_BLKP(ptr);
	if (!GET_ALLOC(HDRP(next_bp)) && GET_SIZE(HDRP(next_bp)) > 0) {
		total = oldsize + GET_SIZE(HDRP(next_bp));
		if (total >= asize) {
			list_remove(next_bp);
			PUT(HDRP(ptr), PACK(total, 1));
			PUT(FTRP(ptr), PACK(total, 1));
			return (ptr);
		}
	}

	/* Fall back: allocate new block, copy, free old */
	newptr = mm_malloc(size);
	if (newptr == NULL)
		return (NULL);
	copy_size = oldsize - DSIZE;  /* old payload size */
	if (size < copy_size)
		copy_size = size;
	memcpy(newptr, ptr, copy_size);
	mm_free(ptr);
	return (newptr);
}

/* ------------------------------------------------------------------
 * Internal helpers
 * ------------------------------------------------------------------ */

/*
 * coalesce - Merge bp with adjacent free blocks, update seg lists.
 *   Returns pointer to the (possibly enlarged) free block.
 */
static void *
coalesce(void *bp)
{
	bool prev_alloc = GET_ALLOC(FTRP(PREV_BLKP(bp)));
	bool next_alloc = GET_ALLOC(HDRP(NEXT_BLKP(bp)));
	size_t size = GET_SIZE(HDRP(bp));

	if (prev_alloc && next_alloc) {
		/* Case 1: no neighbors to merge */
	} else if (prev_alloc && !next_alloc) {
		/* Case 2: merge with next block */
		list_remove(NEXT_BLKP(bp));
		size += GET_SIZE(HDRP(NEXT_BLKP(bp)));
		PUT(HDRP(bp), PACK(size, 0));
		PUT(FTRP(bp), PACK(size, 0));
	} else if (!prev_alloc && next_alloc) {
		/* Case 3: merge with previous block */
		list_remove(PREV_BLKP(bp));
		size += GET_SIZE(HDRP(PREV_BLKP(bp)));
		PUT(FTRP(bp), PACK(size, 0));
		PUT(HDRP(PREV_BLKP(bp)), PACK(size, 0));
		bp = PREV_BLKP(bp);
	} else {
		/* Case 4: merge with both neighbors */
		list_remove(PREV_BLKP(bp));
		list_remove(NEXT_BLKP(bp));
		size += GET_SIZE(HDRP(PREV_BLKP(bp))) +
		        GET_SIZE(HDRP(NEXT_BLKP(bp)));
		PUT(HDRP(PREV_BLKP(bp)), PACK(size, 0));
		PUT(FTRP(NEXT_BLKP(bp)), PACK(size, 0));
		bp = PREV_BLKP(bp);
	}

	list_insert(bp);
	return (bp);
}

/*
 * extend_heap - Extend the heap by 'words' words, coalescing with any
 *   preceding free block.  Returns pointer to the new free block or NULL.
 */
static void *
extend_heap(size_t words)
{
	size_t size;
	void *bp;

	/* Round to even word count for alignment */
	size = (words % 2) ? (words + 1) * WSIZE : words * WSIZE;
	if ((bp = mem_sbrk(size)) == (void *)-1)
		return (NULL);

	PUT(HDRP(bp), PACK(size, 0));           /* Free block header */
	PUT(FTRP(bp), PACK(size, 0));           /* Free block footer */
	PUT(HDRP(NEXT_BLKP(bp)), PACK(0, 1));  /* New epilogue */

	return (coalesce(bp));
}

/*
 * find_fit - Search seg lists for a free block of at least 'asize' bytes.
 *   Starts from the smallest class that could contain a fitting block.
 *   Returns block pointer or NULL.
 */
static void *
find_fit(size_t asize)
{
	int cls = size_class(asize);
	void *bp;

	for (int i = cls; i < NUM_CLASSES; i++) {
		for (bp = get_head(i); bp != NULL; bp = NEXT_FREE(bp)) {
			if (GET_SIZE(HDRP(bp)) >= asize)
				return (bp);
		}
	}
	return (NULL);
}

/*
 * place - Allocate 'asize' bytes in free block bp.
 *   Splits the block if the remainder is at least MIN_BLOCK bytes.
 */
static void
place(void *bp, size_t asize)
{
	size_t csize = GET_SIZE(HDRP(bp));

	list_remove(bp);

	if (csize - asize >= MIN_BLOCK) {
		/* Split: allocate asize, free remainder */
		PUT(HDRP(bp), PACK(asize, 1));
		PUT(FTRP(bp), PACK(asize, 1));
		bp = NEXT_BLKP(bp);
		PUT(HDRP(bp), PACK(csize - asize, 0));
		PUT(FTRP(bp), PACK(csize - asize, 0));
		list_insert(bp);
	} else {
		/* Use entire block */
		PUT(HDRP(bp), PACK(csize, 1));
		PUT(FTRP(bp), PACK(csize, 1));
	}
}

/* ------------------------------------------------------------------
 * Heap consistency checker
 * ------------------------------------------------------------------ */

/*
 * checkblock - Minimal per-block consistency check.
 */
static void
checkblock(void *bp)
{
	if ((uintptr_t)bp % WSIZE)
		printf("Error: %p is not word-aligned\n", bp);
	if (GET(HDRP(bp)) != GET(FTRP(bp)))
		printf("Error: header does not match footer at %p\n", bp);
}

/*
 * checkheap - Scan heap for consistency errors.
 *   Checks prologue/epilogue, alignment, and header/footer agreement.
 *   For free blocks, verifies they appear in the correct seg list.
 */
void
checkheap(bool verbose)
{
	void *bp;

	if (verbose)
		printf("Heap (%p):\n", heap_listp);

	if (GET_SIZE(HDRP(heap_listp)) != DSIZE ||
	    !GET_ALLOC(HDRP(heap_listp)))
		printf("Bad prologue header\n");
	checkblock(heap_listp);

	for (bp = heap_listp; GET_SIZE(HDRP(bp)) > 0; bp = NEXT_BLKP(bp)) {
		if (verbose)
			printblock(bp);
		checkblock(bp);
		/* Check no two consecutive free blocks (coalescing failure) */
		if (!GET_ALLOC(HDRP(bp)) && !GET_ALLOC(HDRP(NEXT_BLKP(bp))))
			printf("Error: consecutive free blocks at %p\n", bp);
	}

	if (verbose)
		printblock(bp);
	if (GET_SIZE(HDRP(bp)) != 0 || !GET_ALLOC(HDRP(bp)))
		printf("Bad epilogue header\n");

	/* Check seg list integrity */
	for (int i = 0; i < NUM_CLASSES; i++) {
		for (bp = get_head(i); bp != NULL; bp = NEXT_FREE(bp)) {
			if (GET_ALLOC(HDRP(bp)))
				printf("Error: allocated block in free list, class %d\n", i);
			if (PREV_FREE(bp) != NULL &&
			    NEXT_FREE(PREV_FREE(bp)) != bp)
				printf("Error: inconsistent prev/next pointers at %p\n", bp);
		}
	}
}

/*
 * printblock - Print header/footer info for a block.
 */
static void
printblock(void *bp)
{
	size_t hsize, fsize;
	bool halloc, falloc;

	hsize  = GET_SIZE(HDRP(bp));
	halloc = GET_ALLOC(HDRP(bp));
	fsize  = GET_SIZE(FTRP(bp));
	falloc = GET_ALLOC(FTRP(bp));

	if (hsize == 0) {
		printf("%p: end of heap\n", bp);
		return;
	}

	printf("%p: header: [%zu:%c] footer: [%zu:%c]\n", bp,
	    hsize, (halloc ? 'a' : 'f'),
	    fsize, (falloc ? 'a' : 'f'));
}

